import{V as t}from"./chunks/theme.DZcTFywn.js";import{c as o,o as r,j as a,a2 as s,a as i,G as n,k as l}from"./chunks/framework.DDIT__tB.js";const d={class:"tip custom-block"},g=JSON.parse('{"title":"📊 Model: (AccessControl-ABAC-violation)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/dfd/AC-ABAC-violation.md","filePath":"examples/models/dfd/AC-ABAC-violation.md"}'),c={name:"examples/models/dfd/AC-ABAC-violation.md"},p=Object.assign(c,{setup(h){return(m,e)=>(r(),o("div",null,[e[2]||(e[2]=a("h1",{id:"📊-model-accesscontrol-abac-violation",tabindex:"-1"},[i("📊 Model: (AccessControl-ABAC-violation) "),a("a",{class:"header-anchor",href:"#📊-model-accesscontrol-abac-violation","aria-label":'Permalink to "📊 Model: (AccessControl-ABAC-violation)"'},"​")],-1)),a("div",d,[e[0]||(e[0]=a("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=a("p",null,"This model is available to view using the online editor!",-1)),n(l(t),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/AC-abac-violation/abac-violation.json"})]),e[3]||(e[3]=s('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://www.scitepress.org/Link.aspx?doi=10.5220/0010515300260037" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/AC-abac-violation" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>The case is about a banking system deployed in the USA and Asia. Clerks can register customers, look them up and determine a credit line for them. Managers can do everything Clerks can do but can also register celebrities or move customers between regions.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><p>None.</p><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p>The <strong>Clerk US</strong> can register regular customers by <em>customer_details</em>. These customers are stored in the <strong>Customer Storage</strong> and can be found by <em>customer_name</em>. The <strong>Manager</strong> located in the US can <strong>Register Celebrity</strong> into a seperate <strong>Celebrity Customer Storage</strong>. Neither Clerk can access this data. The <strong>Manager</strong> can also change the customer location from <code>USA</code> to <code>Asia</code> via the node <strong>Move Customer</strong>. The <em>customer</em> is fetched by <em>customer_name</em> and stored into a <strong>Customer Storage</strong> with the changed <strong>DataOrigin</strong> label. Now, the <strong>Clerk Asia</strong> is able to find this <em>customer</em>.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><strong>DataOrigin</strong>: Shows the originating region of a customer. This can be either <code>USA</code> or <code>Asia</code>.</li><li><strong>DataStatus</strong>: This differentiates between <code>Customer</code> and <code>Celebrity</code>.</li></ul><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><strong>NodeRole</strong>: This label designates an actor as <code>Clerk</code> or <code>Manager</code>.</li><li><strong>NodeLocation</strong>: Shows the location of a clerk or manager in the banking system. This can be either <code>USA</code> or <code>Asia</code>.</li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><p>Clerks are not supposed to be able to access Celebrity customer data. <code>- Security: data DataStatus.Celebrity neverFlows vertex NodeRole.Clerk</code></p><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><p>The introduced flow <em>celebrity_customer_details</em> lets <code>Celebrity</code> data data flows into the normal <strong>Customer Storage</strong>, which the <strong>Clerk US</strong> can access.</p>',18))]))}});export{g as __pageData,p as default};
